/**
 * Pure runtime/addon contract for player-operated resource generators.
 *
 * GameObject and custom wood item IDs are generated by TSWoW, so consumers
 * resolve entryTag/output.tag with UTAG after `build data` instead of freezing
 * generated numeric IDs in source.
 */

export const RESOURCE_GENERATOR_KEY_START = 200;
export const RESOURCE_GENERATOR_KEY_END = 251;
export const RESOURCE_GENERATOR_COST = 40;
export const RESOURCE_GENERATOR_PERIOD_S = 30 * 60;
export const RESOURCE_GENERATOR_DOUBLE_READY_S = 60 * 60;
export const RESOURCE_GENERATOR_CAST_MS = 3000;

export const TAG_RESOURCE_GENERATOR_PLACE_SPELL = "spell/resource-generator-place";
export const TAG_RESOURCE_GENERATOR_PLACE_ITEM = "item/resource-generator-place";
export const TAG_RESOURCE_GENERATOR_GATHER_SPELL = "spell/resource-generator-gather";
export const TAG_RESOURCE_GENERATOR_READY_EFFECT = "go/resource-generator-ready-effect";

export interface ResourceGeneratorYield {
    count: number;
    weight: number;
}

/** One weighted roll per harvest; waiting an hour doubles the result, never beyond x2. */
export const RESOURCE_GENERATOR_YIELDS: ResourceGeneratorYield[] = [
    { count: 3, weight: 60 },
    { count: 5, weight: 30 },
    { count: 10, weight: 10 },
];

export type ResourceGeneratorCategory = "ore" | "herb" | "stone" | "wood" | "fish" | "junk";
export type ResourceGeneratorSkill = "mining" | "herbalism" | "woodcutting" | "fishing";
export type ResourceGeneratorOutputPool = "" | "junk";

export interface ResourceGeneratorItemRef {
    /** Stock item entry; zero when tag contains a generated custom item. */
    entry: number;
    /** Unique TSWoW tag; empty for stock items. */
    tag: string;
    nameEn: string;
    nameRu: string;
}

export interface ResourceGeneratorCost {
    item: ResourceGeneratorItemRef;
    count: number;
}

export interface ResourceGeneratorDef {
    key: number;
    id: string;
    nameEn: string;
    nameRu: string;
    category: ResourceGeneratorCategory;
    /** Numeric gameobject_template entry, filled by hydrateResourceGeneratorCatalog in livescripts. */
    entry: number;
    /** Resolve this unique tag to the generated gameobject_template entry. */
    entryTag: string;
    output: ResourceGeneratorItemRef;
    /** Non-empty only for random salvage pools. */
    outputPool: ResourceGeneratorOutputPool;
    cost: ResourceGeneratorCost;
    skill: ResourceGeneratorSkill;
    requiredSkill: number;
    castMs: number;
    periodS: number;
    doubleReadyS: number;
    /** Stock visual donor used only by datascripts. */
    sourceEntry: number;
    /** Overrides the donor display when non-zero (custom trees). */
    display: number;
    /** Overrides the donor scale when non-zero (custom trees). */
    size: number;
    nativeFishing: boolean;
}

interface ResourceGeneratorSeed {
    id: string;
    category: ResourceGeneratorCategory;
    outputEntry: number;
    outputTag: string;
    outputNameEn: string;
    outputNameRu: string;
    skill: ResourceGeneratorSkill;
    requiredSkill: number;
    sourceEntry: number;
    display?: number;
    size?: number;
    outputPool?: ResourceGeneratorOutputPool;
    costEntry?: number;
    costNameEn?: string;
    costNameRu?: string;
}

