function item(entry: number, tag: string, nameEn: string, nameRu: string): ResourceGeneratorItemRef {
    return { entry: entry, tag: tag, nameEn: nameEn, nameRu: nameRu };
}

function generatorName(category: ResourceGeneratorCategory, resource: string, ru: boolean): string {
    if (category == "fish") return ru ? `Лунка: ${resource}` : `Fishing Hole: ${resource}`;
    if (category == "junk") return resource;
    return ru ? `Генератор: ${resource}` : `${resource} Generator`;
}

export function resourceGeneratorEntryTag(id: string): string {
    return `go/resource-generator-${id}`;
}

export const RESOURCE_GENERATORS: ResourceGeneratorDef[] = SEEDS.map((seed, index) => {
    const output = item(seed.outputEntry, seed.outputTag, seed.outputNameEn, seed.outputNameRu);
    const cost = seed.costEntry === undefined
        ? item(output.entry, output.tag, output.nameEn, output.nameRu)
        : item(seed.costEntry, "", seed.costNameEn || "", seed.costNameRu || "");
    return {
        key: RESOURCE_GENERATOR_KEY_START + index,
        id: seed.id,
        nameEn: generatorName(seed.category, seed.outputNameEn, false),
        nameRu: generatorName(seed.category, seed.outputNameRu, true),
        category: seed.category,
        entry: 0,
        entryTag: resourceGeneratorEntryTag(seed.id),
        output: output,
        outputPool: seed.outputPool || "",
        cost: { item: cost, count: RESOURCE_GENERATOR_COST },
        skill: seed.skill,
        requiredSkill: seed.requiredSkill,
        castMs: RESOURCE_GENERATOR_CAST_MS,
        periodS: RESOURCE_GENERATOR_PERIOD_S,
        doubleReadyS: RESOURCE_GENERATOR_DOUBLE_READY_S,
        sourceEntry: seed.sourceEntry,
        display: seed.display || 0,
        size: seed.size || 0,
        nativeFishing: seed.category == "fish" || seed.category == "junk",
    };
});

/** Existing saved mine/garden rows remain valid and behave as the first exact generator of their profession. */
export const LEGACY_RESOURCE_GENERATOR_ALIASES = [
    { legacyKey: 75, generatorKey: 200 }, // generic mine -> copper ore
    { legacyKey: 76, generatorKey: 213 }, // generic herb garden -> peacebloom
];

/**
 * Livescripts pass literal UTAG results here once at startup. Literal calls stay
 * outside the shared file because TSWoW resolves tags while compiling scripts.
 */
export function hydrateResourceGeneratorCatalog(entries: number[], woodItems: number[]): void {
    hydrateResourceGeneratorEntries(entries);
    hydrateResourceGeneratorWoodItems(woodItems);
}

export function hydrateResourceGeneratorEntries(entries: number[]): void {
    if (entries.length != RESOURCE_GENERATORS.length) {
        throw new Error(`expected ${RESOURCE_GENERATORS.length} resource generator entries, got ${entries.length}`);
    }
    for (let i = 0; i < RESOURCE_GENERATORS.length; i++) {
        RESOURCE_GENERATORS[i].entry = entries[i];
    }
}

/** Addon-safe hydration: BaseState already carries these six custom item IDs. */
export function hydrateResourceGeneratorWoodItems(woodItems: number[]): void {
    if (woodItems.length != 6) throw new Error(`expected 6 wood item entries, got ${woodItems.length}`);
    let woodIndex = 0;
    for (let i = 0; i < RESOURCE_GENERATORS.length; i++) {
        const def = RESOURCE_GENERATORS[i];
        if (def.output.tag != "") {
            def.output.entry = woodItems[woodIndex++];
            def.cost.item.entry = def.output.entry;
        }
    }
}

export function resourceGeneratorByKey(key: number): ResourceGeneratorDef | undefined {
    for (let i = 0; i < LEGACY_RESOURCE_GENERATOR_ALIASES.length; i++) {
        if (LEGACY_RESOURCE_GENERATOR_ALIASES[i].legacyKey == key) {
            key = LEGACY_RESOURCE_GENERATOR_ALIASES[i].generatorKey;
            break;
        }
    }
    const index = key - RESOURCE_GENERATOR_KEY_START;
    return index >= 0 && index < RESOURCE_GENERATORS.length ? RESOURCE_GENERATORS[index] : undefined;
}

/** Small build-time/self-check: catches key drift and accidental non-matching 40-resource costs. */
export function validateResourceGeneratorCatalog(): string[] {
    const errors: string[] = [];
    if (RESOURCE_GENERATORS.length != RESOURCE_GENERATOR_KEY_END - RESOURCE_GENERATOR_KEY_START + 1) {
        errors.push("resource generator count does not match reserved key range");
    }
    for (let i = 0; i < RESOURCE_GENERATORS.length; i++) {
        const def = RESOURCE_GENERATORS[i];
        if (def.key != RESOURCE_GENERATOR_KEY_START + i) errors.push(`non-contiguous generator key ${def.key}`);
        if (def.cost.count != RESOURCE_GENERATOR_COST) errors.push(`invalid construction cost for ${def.id}`);
        if (def.outputPool == "") {
            if (def.output.entry != def.cost.item.entry || def.output.tag != def.cost.item.tag) {
                errors.push(`construction resource differs from output for ${def.id}`);
            }
        } else if (def.cost.item.entry <= 0) {
            errors.push(`random generator ${def.id} has no anchor cost item`);
        }
    }
    return errors;
}
